function sortNumbers(numbers, order) {
  const temp = [];
  for (let i = 0; i < order.length; i++) {
    temp[order[i]] = numbers[i];
  }
  const orderedNumbers = [];
  for (let i = 0; i < temp.length; i++) {
    orderedNumbers.push(temp[i]);
  }
  // Cách giải khác đơn giản hơn: return order.map(i => numbers[i]);
  // Tuy nhiên cách trên không hoàn toàn giống mapOrder, cách giải đúng logic mapOrder:
  const clonedNumbers = [...numbers];
  clonedNumbers.sort((a, b) => order.indexOf(numbers.indexOf(a)) - order.indexOf(numbers.indexOf(b)));
  return clonedNumbers;
}

